struct Employee {
    std::string name;
    std::vector<int> salaries;
};

struct TreeNode {
    std::string name;
    int maxSalary;
    std::vector<TreeNode*> children;
};

int getMaxSalary(const std::vector<int>& salaries) {
    return *std::max_element(salaries.begin(), salaries.end());
}

TreeNode* createEmployeeTree(const std::vector<Employee>& employees, const std::vector<std::pair<std::string, std::string>>& hierarchy) {
    std::unordered_map<std::string, TreeNode*> nodes;
    for (const auto& e : employees) {
        nodes[e.name] = new TreeNode{e.name, getMaxSalary(e.salaries), {}};
    }

    for (const auto& [manager, employee] : hierarchy) {
        if (nodes[manager]->children.size() < 2 && nodes[manager]->children.size() < 3) {
            nodes[manager]->children.push_back(nodes[employee]);
        }
    }

    for (const auto& [manager, employee] : hierarchy) {
        if (nodes[employee]->children.empty()) {
            nodes.erase(employee);
        }
    }

    return nodes.empty() ? nullptr : nodes.begin()->second;
}

int main() {
    // Example usage
    std::vector<Employee> employees = {
        {"Alice", {50000, 55000, 60000}},
        {"Bob", {45000, 48000, 50000}},
        {"Charlie", {70000, 72000, 75000}},
        {"Dave", {30000, 32000, 35000}}
    };

    std::vector<std::pair<std::string, std::string>> hierarchy = {
        {"Alice", "Bob"},
        {"Alice", "Charlie"},
        {"Bob", "Dave"}
    };

    TreeNode* root = createEmployeeTree(employees, hierarchy);

    // Print root details
    if (root) {
        std::cout << "Root: " << root->name << ", Max Salary: " << root->maxSalary << std::endl;
