            this.id = id;
            this.salary = salary;
        }
    }

    static class Edge {
        int node1;
        int node2;
        int salaryDifference;

        Edge(int node1, int node2, int salaryDifference) {
            this.node1 = node1;
            this.node2 = node2;
            this.salaryDifference = salaryDifference;
        }

        @Override
        public String toString() {
            return String.format("Edge(%d, %d, Difference: %d)", node1, node2, salaryDifference);
        }
    }

    public static List<Edge> computeGraph(String filePath) {
        List<Employee> employees = readEmployeesFromFile(filePath);
        List<Edge> edges = new ArrayList<>();
        int edgeCount = 0;

        for (int i = 0; i < employees.size(); i++) {
            for (int j = i + 1; j < employees.size(); j++) {
                int diff = Math.abs(employees.get(i).salary - employees.get(j).salary);
                if (diff < 5000 && edgeCount < 50) {
                    edges.add(new Edge(employees.get(i).id, employees.get(j).id, diff));
                    edgeCount++;
                }
            }
        }
        return edges;
    }

    private static List<Employee> readEmployeesFromFile(String filePath) {
        List<Employee> employees = new ArrayList<>();
        try {
            ObjectMapper objectMapper = new ObjectMapper();
            JsonNode rootNode = objectMapper.readTree(new File(filePath));
            for (JsonNode node : rootNode) {
                int id = node.get("id").asInt();
                int salary = node.get("salary").asInt();
                if (id >= 100 && id <= 999) {
                    employees.add(new Employee(id, salary));
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
        return employees;
    }

    public static void main(String[] args) {
