    std::sort(sortedEmployees.begin(), sortedEmployees.end());

    std::tuple<int, int, int> totals;
    for (size_t i = 0; i < sortedEmployees.size(); ++i) {
        int totalHours = std::clamp(sortedEmployees[i].second, 0, 160);
