    nodes.insert(0, TreeNode { id: 0, children: Vec::new() });

    for (id, parent_id) in tuples {
        if parent_id == 0 || nodes.contains_key(&parent_id) {
            let parent_node = nodes.get_mut(&parent_id);
            if let Some(parent) = parent_node {
                if parent.children.len() < 2 {
                    nodes.insert(
                        id,
                        TreeNode { id, children: Vec::new() },
                    );
                    parent.children.push(nodes[&id].clone());
                }
            }
        }
    }

    fn is_valid_depth(root: &TreeNode, depth: usize) -> bool {
        if depth > 3 {
            return false;
        }
        for child in &root.children {
            if !is_valid_depth(child, depth + 1) {
                return false;
            }
        }
        true
    }

    let root = nodes.get(&0).cloned();
    if let Some(root_node) = root {
        if is_valid_depth(&root_node, 1) {
            return Some(root_node);
        }
    }

    None
}

fn main() {
    let tuples = vec![(1, 0), (2, 0), (3, 1), (4, 1), (5, 2)];
    let tree = create_tree_from_tuples(tuples);
    println!("{:?}", tree);
}
