use std::collections::HashSet;
use chrono::{Utc, Duration};

fn get_unique_timestamps_in_last_hour(timestamps: Vec<i64>) -> HashSet<i64> {
    let current_time = Utc::now().timestamp();
    let one_hour_ago = current_time - Duration::hours(1).num_seconds();

    let unique_timestamps: HashSet<_> = timestamps.into_iter()
        .filter(|&ts| ts > one_hour_ago && ts <= current_time)
        .collect();

    unique_timestamps.into_iter().take(10).collect()
}
