import json

def categorize_users_by_age(json_data):
    data = json.loads(json_data)
    categorized_users = {}

    for user in data['users']:
        age = user['age']
        if 20 <= age <= 60:
            age_category = f"{age//10*10}-{age//10*10+9}"
            if age_category not in categorized_users:
                categorized_users[age_category] = []
            categorized_users[age_category].append(user)

    return json.dumps(categorized_users, indent=4)
